[DataContractAttribute,SysOperationAlwaysInitializeAttribute, SysOperationContractProcessingAttribute(classstr(ETGRminCocoaUIBuilder))]
public class ETGRminCocoaContract implements SysOperationValidatable,SysOperationInitializable//implements SysOperationInitializable//implements SysOperationValidatable
{
    TransDate                   FromDate;
    TransDate                   ToDate;
    List                        VendAccount;
    List                        InvoiceId;
    List                        ItemId;
}

Method.Source:
public void initialize()

{

    VendAccount =null;
    InvoiceId   =null;
    ItemId      =null;
    FromDate = dateNull();
    ToDate   = dateNull();

}

[DataMemberAttribute('FromDate'), SysOperationLabelAttribute("From Date"), SysOperationDisplayOrderAttribute('1')]
public TransDate parmFromDate(TransDate _FromDate = FromDate)
{
    FromDate = _FromDate;

    return FromDate;
}

[DataMemberAttribute('ToDate'), SysOperationLabelAttribute("To Date"), SysOperationDisplayOrderAttribute('2')]
public Transdate parmToDate(TransDate _ToDate = ToDate)
{
    ToDate = _ToDate;

    return ToDate;
}

[DataMemberAttribute("VendAccount"),AifCollectionTypeAttribute("Vend Account", Types::String),
   SysOperationLabelAttribute(literalStr("Vendor Account")),SysOperationDisplayOrderAttribute('3')]
public List parmVendAccount(List _VendAccount= VendAccount)
{
    VendAccount = _VendAccount;

    return VendAccount;
}

[DataMemberAttribute("InvoiceId"),AifCollectionTypeAttribute("Invoice Id", Types::String),
   SysOperationLabelAttribute(literalStr("Invoice Id")),SysOperationDisplayOrderAttribute('4')]
public List parmInvoiceId(List _InvoiceId= InvoiceId)
{
    InvoiceId = _InvoiceId;
    return InvoiceId;
}

[DataMemberAttribute("ItemId"),AifCollectionTypeAttribute("Item Id", Types::String),
   SysOperationLabelAttribute(literalStr("Item Id")),SysOperationDisplayOrderAttribute('5')]
public List parmItemId(List _ItemId= ItemId)
{
    ItemId = _ItemId;
    return ItemId;
}

